const body = await insomnia.response.json();
const data = body && body.response;
if (data?.access_token) await insomnia.environment.set('access_token', data.access_token);
if (data?.refresh_token) await insomnia.environment.set('refresh_token', data.refresh_token);
if (data?.user?.id) {
  await insomnia.environment.set('current_user_id', data.user.id);
  await insomnia.environment.set('lookup_user_id', data.user.id);
}
if (data?.user?.username) await insomnia.environment.set('username', data.user.username);
console.log('[auth] register response processed');

