const body = await insomnia.response.json();
const list = body && body.response;
if (Array.isArray(list)) {
  const active = list.find(item => item && item.is_active);
  if (active?.id) await insomnia.environment.set('invite_id', active.id);
  if (active?.code) await insomnia.environment.set('invite_code', active.code);
}
